import{_ as p,C as t,o as c,c as g,j as e,a as n,E as i,a3 as m}from"./chunks/framework.gsMzR_Kb.js";const y=JSON.parse('{"title":"太上感应篇","description":"一篇从善恶感应落到日用警策的劝善短文。","frontmatter":{"title":"太上感应篇","description":"一篇从善恶感应落到日用警策的劝善短文。","category":"guide","aliases":["太上感应篇","感应篇","taishang ganying pian"],"source":["《太上感应篇》"]},"headers":[],"relativePath":"daoism/starter-texts/taishang-ganying-pian.md","filePath":"daoism/starter-texts/taishang-ganying-pian.md","lastUpdated":1777132262000}'),u={name:"daoism/starter-texts/taishang-ganying-pian.md"};function b(x,a,_,P,f,q){const r=t("DaoReadingPrelude"),o=t("DaoOriginalReading"),l=t("DaoLineGuide"),s=t("DaoPinyinGlossary"),d=t("DaoParallelReading"),h=t("DaoKeywordCards");return c(),g("div",null,[a[0]||(a[0]=e("h1",{id:"太上感应篇",tabindex:"-1"},[n("太上感应篇 "),e("a",{class:"header-anchor",href:"#太上感应篇","aria-label":'Permalink to "太上感应篇"'},"​")],-1)),i(r,{title:"先抓住感应总纲，再看善恶条目",summary:"这篇不从玄理起，而是直接立出“祸福无门，惟人自召”的总纲。更适合的进入方式，是先顺着原文感受整篇的警策语气，再按总纲、善行、恶行、改悔四层慢慢分开读。",points:[{label:"先读",text:"先把开篇总纲与结尾改悔完整读一遍。"},{label:"再辨",text:"看善恶条目怎样从日用细处展开。"},{label:"后想",text:"最后回到“转祸为福”的余地，不把全篇只读成惩戒。"}],hint:"这篇篇幅较长，第一次读不必逐条硬记，可先抓住总纲、善行举要、恶行举列、改过迁善四个层次。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(o,{paragraphs:["太上曰：祸福无门，惟人自召；善恶之报，如影随形。","是以天地有司过之神，依人所犯轻重，以夺人算。算减则贫耗，多逢忧患；人皆恶之，刑祸随之；吉庆避之，恶星灾之；算尽则死。又有三台北斗神君，在人头上，录人罪恶，夺其纪算。又有三尸神，在人身中，每到庚申日，辄上诣天曹，言人罪过。月晦之日，灶神亦然。凡人有过，大则夺纪，小则夺算。其过大小，有数百事，欲求长生者，先须避之。","是道则进，非道则退。不履邪径，不欺暗室；积德累功，慈心于物；忠孝友悌，正己化人；矜孤恤寡，敬老怀幼；昆虫草木，犹不可伤。","宜悯人之凶，乐人之善，济人之急，救人之危；见人之得，如己之得；见人之失，如己之失；不彰人短，不炫己长；遏恶扬善，推多取少；受辱不怨，受宠若惊；施恩不求报，与人不追悔；所谓善人，人皆敬之，天道佑之，福禄随之，众邪远之，神灵卫之；所作必成，神仙可冀。欲求天仙者，当立一千三百善；欲求地仙者，当立三百善。","苟或非义而动，背理而行；以恶为能，忍作残害；阴贼良善，暗侮君亲；慢其先生，叛其所事；诳诸无识，谤诸同学；虚诬诈伪，攻讦宗亲；刚强不仁，狠戾自用；是非不当，向背乖宜；虐下取功，谄上希旨；受恩不感，念怨不休；轻蔑天民，扰乱国政；赏及非义，刑及无辜；杀人取财，倾人取位；诛降戮服，贬正排贤；凌孤逼寡，弃法受赂；以直为曲，以曲为直；入轻为重，见杀加怒；知过不改，知善不为；自罪引他，壅塞方术；诅咒求直，嗜酒悖乱；骨肉忿争，男不忠良，女不柔顺；不和其室，不敬其夫；每好矜夸，常行妒忌；无行于妻子，失礼于舅姑；轻慢先灵，违逆上命；作为无益，怀挟外心；自咒咒他，偏憎偏爱；越井越灶，跳食跳人；损子堕胎，行多隐僻；晦腊歌舞，朔旦号怒；对北涕唾及溺，对灶吟咏及哭；又以灶火烧香，秽柴作食；夜起裸露，八节行刑；唾流星，指虹霓，辄指三光；久视日月，春月燎猎；对北恶骂，无故杀龟打蛇；如是等罪，司命随其轻重，夺其纪算。算尽则死，死有余责，乃殃及子孙。","又诸横取人财者，乃计其妻子家口以当之，渐至死丧。若不死丧，则有水火盗贼、遗亡器物、疾病口舌诸事，以当妄取之值。又枉杀人者，是易刀兵而相杀也。取非义之财者，譬如漏脯救饥，鸩酒止渴，非不暂饱，死亦及之。","夫心起于善，善虽未为，而吉神已随之；或心起于恶，恶虽未为，而凶神已随之。其有曾行恶事，后自改悔，诸恶莫作，众善奉行，久久必获吉庆；所谓转祸为福也。故吉人语善、视善、行善，一日有三善，三年天必降之福；凶人语恶、视恶、行恶，一日有三恶，三年天必降之祸。胡不勉而行之？"]}),i(l,{lines:[{text:"太上曰：祸福无门，惟人自召；善恶之报，如影随形。",tone:"总纲 · 先立根本",guide:"开篇先不要急着进入神祇系统，先抓住全篇真正的中心：祸福与善恶都与人的起心动念和所作所为相连。"},{text:"是以天地有司过之神……欲求长生者，先须避之。",tone:"秩序 · 强化警惕",guide:"这一段可先读成“天地间有一套追索人过的秩序”，重点不只在神名，而在于强调人的行为并不会做过就算。"},{text:"是道则进……欲求地仙者，当立三百善。",tone:"善行 · 落到日用",guide:"善并不是空泛口号，而是落实在不欺暗室、敬老怀幼、见人得失如己得失这些很具体的日常分寸里。"},{text:"苟或非义而动……乃殃及子孙。",tone:"恶行 · 镜照自身",guide:"这一长段不必一次记全，更适合当作一面镜子，看许多败坏与祸乱如何由细小偏差不断积成。"},{text:"夫心起于善……胡不勉而行之？",tone:"转向 · 留有余地",guide:"全篇最后不是把人锁死，而是留下改悔与转祸为福的路，这也是读这篇时很重要的收束处。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】注音-生僻字",tabindex:"-1"},[n("【原典层】注音 / 生僻字 "),e("a",{class:"header-anchor",href:"#【原典层】注音-生僻字","aria-label":'Permalink to "【原典层】注音 / 生僻字"'},"​")],-1)),i(s,{description:"这篇警策语气很强，先把常见却容易读错的字扫清，再回到句义。",items:[{char:"悌",pinyin:"tì",tag:"伦理字",note:"友悌，指兄弟之间和顺相处。"},{char:"恤",pinyin:"xù",tag:"常见误读",note:"恤寡之恤，有体察、抚恤之意。"},{char:"炫",pinyin:"xuàn",tag:"常见字",note:"炫己长，即夸耀自己的长处。"},{char:"讦",pinyin:"jié",tag:"生僻字",note:"攻讦，指揭人隐私、攻击他人短处。"},{char:"戾",pinyin:"lì",tag:"生僻字",note:"狠戾，指刚狠乖张，不近情理。"},{char:"鸩",pinyin:"zhèn",tag:"比喻字",note:"鸩酒，比喻看似止急，实则害命。"}]}),a[3]||(a[3]=e("h2",{id:"【原典层】分段",tabindex:"-1"},[n("【原典层】分段 "),e("a",{class:"header-anchor",href:"#【原典层】分段","aria-label":'Permalink to "【原典层】分段"'},"​")],-1)),i(d,{sections:[{label:"总纲",original:"太上曰：祸福无门，惟人自召；善恶之报，如影随形。",reading:"祸福无门，惟人自召；善恶之报，如影随形。",translation:"祸福并不是无端撞上来的，常常与人自己所召成的因由相关；善恶的结果，也会像影子一样慢慢跟上来。"},{label:"司过夺算",original:"是以天地有司过之神……欲求长生者，先须避之。",reading:"是以天地有司过之神 / 依人所犯轻重，以夺人算……欲求长生者，先须避之。",translation:"经文借司过、夺算的秩序语言，强调人的一举一动并非无后果，而是始终落在更大的衡量之中。",note:"这里的重点不是神秘细节本身，而是“有过必有追索”的警惕感。"},{label:"善行举要",original:"是道则进……欲求地仙者，当立三百善。",reading:"是道则进，非道则退……所谓善人，人皆敬之，天道佑之……欲求地仙者，当立三百善。",translation:"善并不飘在高处，而是一条条落在对人、对己、对物的具体分寸中；经文借此把“善”从抽象拉回日用。"},{label:"恶行举列",original:"苟或非义而动……乃殃及子孙。",reading:"苟或非义而动，背理而行……如是等罪，司命随其轻重，夺其纪算。算尽则死，死有余责，乃殃及子孙。",translation:"这一段集中铺开各种恶行，提醒人许多大的败坏与灾祸，往往都是从细小偏差、贪取、欺瞒与刚愎中慢慢积成。"},{label:"改过迁善",original:"又诸横取人财者……胡不勉而行之？",reading:"夫心起于善，善虽未为，而吉神已随之；或心起于恶，恶虽未为，而凶神已随之……胡不勉而行之？",translation:"全篇并未把人锁死在定罪里，而是指出：若能真正改悔、止恶行善，仍然有机会把后面的路慢慢转过来。"}]}),a[4]||(a[4]=e("h2",{id:"【原典层】关键词",tabindex:"-1"},[n("【原典层】关键词 "),e("a",{class:"header-anchor",href:"#【原典层】关键词","aria-label":'Permalink to "【原典层】关键词"'},"​")],-1)),i(h,{items:[{term:"感应",meaning:"人的起心动念与行为，终会带来相应后果。",context:"这不是空泛报应论，而是整篇最根本的警策逻辑。"},{term:"祸福",meaning:"并非无端降临，而与人的选择、习气与行为相关。",context:"经文开篇就把祸福拉回“惟人自召”的脉络里。"},{term:"司过",meaning:"象征记录、衡量、追索人过的一套秩序。",context:"可先理解为古典语境中的“行为不会凭空消失”。"},{term:"纪算",meaning:"寿数、福分、命数的古典表达。",context:"经文借此强化“过失会折损人的生命秩序”这一感受。"},{term:"善恶",meaning:"不只是抽象判断，而是落在具体言行、待人、处事上。",context:"整篇最重要的特点，就是把善恶拆成一条条可自照的日用行为。"},{term:"改悔",meaning:"承认过失、转身回头、重新止恶行善。",context:"全篇最后仍给人留下“转祸为福”的可能，而不只是定罪。"}]}),a[5]||(a[5]=m('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><blockquote><p>解读仅个人观点，仅供参考，若有疏漏还望海涵，并批评指出</p></blockquote><h3 id="象-这篇在说什么" tabindex="-1">象：这篇在说什么 <a class="header-anchor" href="#象-这篇在说什么" aria-label="Permalink to &quot;象：这篇在说什么&quot;">​</a></h3><p>《太上感应篇》开篇就把话说得很直：“祸福无门，惟人自召；善恶之报，如影随形。”后面整篇几乎都围绕这一点展开：人的念头、言语、行为，并不会凭空消散，而会积累、转化，最终回到自己身上。</p><p>它和《清静经》《阴符经》的气质不同，不重在讲大道本体，也不重在讲天机转变，而是更直接地落到日常做人做事上。</p><h3 id="理-为什么这篇重要" tabindex="-1">理：为什么这篇重要 <a class="header-anchor" href="#理-为什么这篇重要" aria-label="Permalink to &quot;理：为什么这篇重要&quot;">​</a></h3><p>这篇重要，不在于它把人吓住，而在于它把“善恶”从空话拉回日用。</p><ul><li>它提醒人，许多后果并不是偶然掉下来的</li><li>它把抽象的“善”与“恶”列成具体行为，让人照见自身</li><li>它没有停在定罪，最后仍留下“改悔”“转祸为福”的路</li><li>它很适合作为一种日常警策，而不是只当作神秘劝善文来读</li></ul><h3 id="用-今天怎么进入这篇" tabindex="-1">用：今天怎么进入这篇 <a class="header-anchor" href="#用-今天怎么进入这篇" aria-label="Permalink to &quot;用：今天怎么进入这篇&quot;">​</a></h3><p>今天读《太上感应篇》，可以先不急着把“司过之神”“夺算”全都读成字面宗教设定，而先抓住它要提醒人的根本问题：</p><ul><li>我平常是不是总把后果归给外界，却很少回看自己？</li><li>我以为自己只是起了个念头、说了一句话，真的没有影响吗？</li><li>若我已经做错了，有没有认真改悔、转向的能力？</li></ul><p>先抓住这些问题，再回头读原文，感受会更深。</p><h2 id="【解读层】分段解读" tabindex="-1">【解读层】分段解读 <a class="header-anchor" href="#【解读层】分段解读" aria-label="Permalink to &quot;【解读层】分段解读&quot;">​</a></h2><h3 id="_1-总纲-祸福并非无端而来" tabindex="-1">1. 总纲：祸福并非无端而来 <a class="header-anchor" href="#_1-总纲-祸福并非无端而来" aria-label="Permalink to &quot;1. 总纲：祸福并非无端而来&quot;">​</a></h3><p>“祸福无门，惟人自召；善恶之报，如影随形”是全篇总纲。它先把最核心的一点立住：祸福不是凭空闯入生活的陌生东西，而往往与人的起心动念和所作所为有关。</p><p>这里的“惟人自召”也不只是一句简单的归责。它更像是在提醒人：祸福不是只在起点上决定的，而会在人的持续应对中不断长出来。事情发生之后，人怎么想、怎么对待自己、怎么继续往前走，也都在把后面的祸福慢慢召成新的样子。</p><p>而“如影随形”也不必先读成吓人的“逃不过”。影子不是外加给人的，它本来就会随着形而生。影不是本体，也不能说明全部，但它会忠实地照出一个轮廓。人的善恶、选择与行事方式也是如此：每个人的心不同，读出来的提醒也不同，可一个人活出来的痕迹，总会慢慢显现。你可以不看它、不想它，但它仍然在那里。</p><h3 id="_2-司过夺算-以秩序感强化警惕" tabindex="-1">2. 司过夺算：以秩序感强化警惕 <a class="header-anchor" href="#_2-司过夺算-以秩序感强化警惕" aria-label="Permalink to &quot;2. 司过夺算：以秩序感强化警惕&quot;">​</a></h3><p>后面大量关于司过之神、三尸神、灶神、夺纪夺算的说法，可以先理解为一种强烈的秩序感表达。它是在告诉人：人的所作所为，并不是做过就算了，而像始终有一套更大的秩序在衡量、记录、追索。</p><h3 id="_3-善行举要-把-善-落到日用里" tabindex="-1">3. 善行举要：把“善”落到日用里 <a class="header-anchor" href="#_3-善行举要-把-善-落到日用里" aria-label="Permalink to &quot;3. 善行举要：把“善”落到日用里&quot;">​</a></h3><p>这一段最重要的地方，在于它并没有把“善”说成空泛的大词，而是落在很具体的人伦和日常里：不欺暗室、慈心于物、见人之得如己之得、不彰人短、不炫己长、施恩不求报。</p><p>它不是让人空谈高远，而是回到平时最容易忽略的地方。</p><h3 id="_4-恶行举列-恶多从细处积成" tabindex="-1">4. 恶行举列：恶多从细处积成 <a class="header-anchor" href="#_4-恶行举列-恶多从细处积成" aria-label="Permalink to &quot;4. 恶行举列：恶多从细处积成&quot;">​</a></h3><p>恶行一段读来很长，也很重。若只把它当作道德清单，容易疲。更好的读法，也许是把它看成一面镜子：很多祸乱与败坏，并不是突然发生，而是从一连串细小的偏差、妄动、贪取、欺瞒、刚愎中慢慢积成。</p><h3 id="_5-改过迁善-不是定罪-而是转向" tabindex="-1">5. 改过迁善：不是定罪，而是转向 <a class="header-anchor" href="#_5-改过迁善-不是定罪-而是转向" aria-label="Permalink to &quot;5. 改过迁善：不是定罪，而是转向&quot;">​</a></h3><p>全篇最后最可贵的一点，是它没有把人锁死在“你做过恶，所以完了”。它仍然说：若能改悔，诸恶莫作，众善奉行，久而久之，仍可“转祸为福”。</p><p>这使它不只是惩戒文，也还是一篇给人留路的文字。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>一个人的祸福并不总是外界强加的，很多时候，它与自己的念头、说话方式和做事方式有关。善恶不会立刻都显出结果，但会像影子一样慢慢跟上来。</p><p>《太上感应篇》不是要人陷入恐惧，而是提醒人：后果往往早在平时就埋下了。若能从细处自省、从日用中改正、从错误里回头，那么命运并非毫无转机。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>这篇给我的第一感觉，是“直”。《清静经》会先把人带到更大的大道秩序里，《阴符经》会让人看见变化与机，而《太上感应篇》像是直接站在你面前说：你不要总怪天怪地，很多祸福本来就和你自己有关。</p><p>我读这篇的入口，其实和自己经历过的一场祸有关。一次骑车意外让我骨折，正好撞在羽毛球比赛前一周。那之后吃饭、敲代码、日常动作都变得很麻烦，整个人也短暂陷进了压抑里。回头看，这件事的源头与我自己有关，所以我也不太愿意把它全推给外界。可也正因为这场祸，我被迫慢下来，开始练另一只手，开始重新适应新的节奏，也是在那段时间里，我真正走近《易经》，走近这些文字。</p><p>所以现在再读“祸福无门，惟人自召”，我会更愿意把它理解成：祸福并不总是贴在事情表面的固定标签。祸来了，未必只停在祸；人怎么应对，怎么转身，后面的路也会慢慢变。那场意外是祸，但它也逼我慢下来，看见周边的世界，宽恕过去的自己，重新开始学习和整理。这样回看时，我反而觉得，福有时正是从祸里慢慢长出来的。</p><p>我觉得它的可贵之处，不只是讲“善恶有报”，而是把这件事讲得很细。不是只说“你要做个好人”，而是把许多平时最容易被忽略的地方一条条摆出来。这样读的时候，人反而很难只停在抽象认同上，因为总会有几句照到自己。</p><p>但我现在也不太愿意把它读成一篇单纯吓人的文章。若只剩恐惧，那人可能只是表面收敛，心里并没有真的转。相比之下，我更在意它最后留的那条路：若曾行恶，后自改悔，诸恶莫作，众善奉行，久久必获吉庆。也就是说，它不是只在追责，也还是在劝人回头。</p><p>而“善恶之报，如影随形”对我来说，也不只是吓人的“报应”说法。人的念头、选择、应对方式，都会像影子一样慢慢跟上来。那段时间里，我开始放下比较，接受自己的平凡，接受一些所谓失败，继续按自己的节奏去做自己觉得正确的事。现在回头看，那些当时看似很小的转念和行动，也都一路跟着我，走到了今天。</p><p>现在再读“惟人自召”，我更愿意把它理解成一种持续生成。人当然要为自己的选择负责，但更重要的是，事情发生之后，自己怎么应对、怎么转向，也都在不断把后面的祸福召出来。这样一来，祸福就不只是外在降临的结果，而像是在人的一念一行里继续长成。</p><p>而“如影随形”对我来说，也越来越像一个更深的比喻。影不是本体，也不能代表全部，但它会很忠实地照出一个轮廓。人的生命状态也是如此：很多事情并不是简单二元的，可即便如此，一个人活出来的走向，仍会慢慢投出自己的影子。这个影未必是为了定罪，反而更像一种善意的提醒，让人看见自己大致正在往哪里去。</p><p>所以这篇我会更愿意把它当作一面镜子。不是天天拿来审判别人，而是偶尔照一照自己：哪些地方已经偏了，哪些地方仍能转回来。若真能从照见自己开始，再一点点改，这篇文字就不是只会让人害怕，而是会真正帮人活得更清醒一些。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《太上感应篇》</li><li><a href="https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%84%9F%E6%87%89%E7%AF%87" target="_blank" rel="noreferrer">维基文库：太上感應篇</a></li></ul>',42))])}const D=p(u,[["render",b]]);export{y as __pageData,D as default};
